import React, { useState, useEffect } from "react";
import axios from "axios";
import "../styles/Contact.css";

const Contact = () => {
  // State management
  const [formData, setFormData] = useState({
    fullName: "",
    email: "",
    phoneNumber: "",
    subject: "",
    message: "",
  });
  
  const [authData, setAuthData] = useState({
    username: "",
    email: "",
    password: "",
    confirmPassword: ""
  });
  
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState(null);
  const [errors, setErrors] = useState({});
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showSignUp, setShowSignUp] = useState(false);
  const [userInfo, setUserInfo] = useState(null);

  // Validation patterns
  const validationRules = {
    fullName: {
      pattern: /^[a-zA-Z\u00C0-\u017F\s'-]{3,100}$/,
      message: "Name must be 3-100 letters with spaces or hyphens"
    },
    email: {
      pattern: /^[^\s@]+@[^\s@]+\.[^\s@]+$/,
      message: "Please enter a valid email address"
    },
    phoneNumber: {
      pattern: /^\+?[\d\s\-\(\)]{6,20}$/,
      message: "Phone must be 6-20 digits with optional +, spaces or hyphens",
      required: false
    },
    subject: {
      minLength: 5,
      maxLength: 100,
      message: "Subject must be 5-100 characters"
    },
    message: {
      minLength: 20,
      maxLength: 2000,
      message: "Message must be 20-2000 characters"
    }
  };

  // Check authentication on mount
  useEffect(() => {
    const token = localStorage.getItem("token");
    const user = localStorage.getItem("user");
    if (token && user) {
      setIsLoggedIn(true);
      setUserInfo(JSON.parse(user));
    }
  }, []);

  // Handle form input changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value,
    }));
    
    // Clear error when user types
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: null }));
    }
  };

  // Validate form fields
  const validateField = (name, value) => {
    const rules = validationRules[name];
    if (!rules) return true;
    
    if (rules.required === false && !value) return true;
    
    if (rules.pattern && !rules.pattern.test(value)) {
      return rules.message;
    }
    
    if (rules.minLength && value.length < rules.minLength) {
      return rules.message;
    }
    
    if (rules.maxLength && value.length > rules.maxLength) {
      return rules.message;
    }
    
    return null;
  };

  // Validate entire form
  const validateForm = () => {
    const newErrors = {};
    let isValid = true;
    
    Object.keys(formData).forEach(key => {
      if (key === "phoneNumber" && !formData[key]) return;
      
      const error = validateField(key, formData[key]);
      if (error) {
        newErrors[key] = error;
        isValid = false;
      }
    });
    
    setErrors(newErrors);
    return isValid;
  };

  // Handle contact form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!validateForm()) return;
    
    setIsSubmitting(true);
    
    try {
      const token = localStorage.getItem("token");
      if (!token) throw new Error("Authentication required");

      await axios.post(
        "https://localhost:7235/api/contact", 
        {
          FullName: formData.fullName.trim(),
          Email: formData.email.trim(),
          PhoneNumber: formData.phoneNumber?.trim() || null,
          Subject: formData.subject.trim(),
          Message: formData.message.trim()
        },
        {
          headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
          }
        }
      );

      setSubmitStatus("success");
      setFormData({
        fullName: "",
        email: "",
        phoneNumber: "",
        subject: "",
        message: "",
      });
      setErrors({});
    } catch (err) {
      console.error("Submission error:", err);
      setErrors({
        form: err.response?.data?.message || 
             err.message || 
             "Failed to submit message. Please try again."
      });
      setSubmitStatus("error");
    } finally {
      setIsSubmitting(false);
    }
  };

  // ... [keep your existing auth methods handleLogin, handleSignup, handleLogout] ...

  return (
    <div id="contact" className="contact-container">
      <h1>CONTACT US</h1>

      <div className="map-container">
        <iframe
          title="Google Map"
          className="google-map"
          src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3048.146201882546!2d44.62674911141569!3d40.18355967135914!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x406aa5fb2d2aeb97%3A0x7a90e13129b8e750!2z1Y7VuNaC1aTVvSDUv9Wl1bbVv9aA1bjVtg!5e0!3m2!1shy!2sam!4v1743157411782!5m2!1shy!2sam"
          allowFullScreen
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
        ></iframe>
      </div>

      <div className="contact-content">
        <div className="contact-info">
          <h2>Law Office</h2>
          <div className="info-item">
            <span className="icon">📍</span>
            <div>
              <h3>Address</h3>
              <p>Armenia, Yerevan City</p>
              <p>Woods Centre</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📞</span>
            <div>
              <h3>Phone</h3>
              <p>+374 12 34 56 78</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📧</span>
            <div>
              <h3>E-mail</h3>
              <p>info@law.com</p>
            </div>
          </div>
        </div>

        <div className="contact-form">
          {isLoggedIn ? (
            <>
              <div className="user-header">
                <h3>Welcome, {userInfo?.userName || "User"}!</h3>
                {userInfo?.isAdmin && <span className="admin-badge">ADMIN</span>}
                <button onClick={handleLogout} className="logout-btn">Logout</button>
              </div>
              
              <h4>LEAVE US A MESSAGE</h4>
              
              {errors.form && (
                <div className="error-message">
                  ❌ {errors.form}
                </div>
              )}

              {submitStatus === "success" && (
                <div className="success-message">
                  ✅ Thank you! Your message has been sent.
                </div>
              )}

              <form onSubmit={handleSubmit}>
                <div className="form-group">
                  <input
                    type="text"
                    name="fullName"
                    placeholder="Your Full Name (3-100 characters)"
                    value={formData.fullName}
                    onChange={handleChange}
                    required
                    className={errors.fullName ? "error" : ""}
                  />
                  {errors.fullName && <span className="field-error">{errors.fullName}</span>}
                </div>
                
                <div className="form-group">
                  <input
                    type="email"
                    name="email"
                    placeholder="example@email.com"
                    value={formData.email}
                    onChange={handleChange}
                    required
                    className={errors.email ? "error" : ""}
                  />
                  {errors.email && <span className="field-error">{errors.email}</span>}
                </div>
                
                <div className="form-group">
                  <input
                    type="tel"
                    name="phoneNumber"
                    placeholder="Phone Number (optional) e.g. +37498123456"
                    value={formData.phoneNumber}
                    onChange={handleChange}
                    className={errors.phoneNumber ? "error" : ""}
                  />
                  {errors.phoneNumber && <span className="field-error">{errors.phoneNumber}</span>}
                </div>
                
                <div className="form-group">
                  <input
                    type="text"
                    name="subject"
                    placeholder="Subject (min 5 characters)"
                    value={formData.subject}
                    onChange={handleChange}
                    required
                    className={errors.subject ? "error" : ""}
                  />
                  {errors.subject && <span className="field-error">{errors.subject}</span>}
                </div>
                
                <div className="form-group">
                  <textarea
                    name="message"
                    placeholder="Write your message here... (min 20 characters)"
                    value={formData.message}
                    onChange={handleChange}
                    required
                    className={errors.message ? "error" : ""}
                  ></textarea>
                  {errors.message && <span className="field-error">{errors.message}</span>}
                </div>

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Sending...
                    </>
                  ) : (
                    "Submit Message"
                  )}
                </button>
              </form>
            </>
          ) : showSignUp ? (
            <>
              <h3>SIGN UP</h3>
              
              {error && (
                <div className="error-message">
                  ❌ {error}
                </div>
              )}

              {submitStatus === "success" && (
                <div className="success-message">
                  ✅ Registration successful! Please sign in.
                </div>
              )}

              <form onSubmit={handleSignup}>
                <input
                  type="text"
                  name="username"
                  placeholder="Username"
                  value={authData.username}
                  onChange={handleAuthChange}
                  required
                />
                <input
                  type="email"
                  name="email"
                  placeholder="Email"
                  value={authData.email}
                  onChange={handleAuthChange}
                  required
                />
                <input
                  type="password"
                  name="password"
                  placeholder="Password (min 6 characters)"
                  value={authData.password}
                  onChange={handleAuthChange}
                  required
                />
                <input
                  type="password"
                  name="confirmPassword"
                  placeholder="Confirm Password"
                  value={authData.confirmPassword}
                  onChange={handleAuthChange}
                  required
                />

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Signing Up...
                    </>
                  ) : (
                    "Sign Up"
                  )}
                </button>
              </form>
              
              <p className="auth-switch">
                Already have an account? 
                <button onClick={() => setShowSignUp(false)}>Sign In</button>
              </p>
            </>
          ) : (
            <>
              <h3>SIGN IN</h3>
              
              {error && (
                <div className="error-message">
                  ❌ {error}
                </div>
              )}

              {submitStatus === "success" && (
                <div className="success-message">
                  ✅ Login successful!
                </div>
              )}

              <form onSubmit={handleLogin}>
                <input
                  type="email"
                  name="email"
                  placeholder="Email"
                  value={authData.email}
                  onChange={handleAuthChange}
                  required
                />
                <input
                  type="password"
                  name="password"
                  placeholder="Password"
                  value={authData.password}
                  onChange={handleAuthChange}
                  required
                />

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className={isSubmitting ? "submitting" : ""}
                >
                  {isSubmitting ? (
                    <>
                      <span className="spinner"></span>
                      Signing In...
                    </>
                  ) : (
                    "Sign In"
                  )}
                </button>
              </form>
              
              <p className="auth-switch">
                Don't have an account? 
                <button onClick={() => setShowSignUp(true)}>Sign Up</button>
              </p>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default Contact;
